// Validate the approval payload and normalize it for the send executor.
// Only 'approve' actions are forwarded; anything else is a no-op.
const req = $input.first().json || {};
const b = (req && typeof req.body === 'object' && req.body) ? req.body : req;

if (b.action && b.action !== 'approve') {
  return [{ json: { skip: true, reason: `ignored action: ${b.action}` } }];
}

const draft_id = b.draft_id;
const team_id = b.team_id;
if (!draft_id || !team_id) {
  throw new Error('approval-trigger requires draft_id and team_id');
}

return [{
  json: {
    skip: false,
    draft_id,
    team_id,
    conversation_id: b.conversation_id || null,
    workspace_id: b.workspace_id || null,
  },
}];
